65f773c6.theorem:
theorem sin_div_plus_three_max_min_sum  :
  let f  := fun (x  : ℝ) ↦ (sin x)/(sin x + 3)
  (⨆ x, f x) + (⨅ x, f x) = -1/4 := by

a1afcc78.theorem:
theorem log_function_range_13  : 
  let M  := {x  : ℝ | 1 < x ∧ x < 3}
  let f (x  : ℝ)  := 2^(x+2) - 4^x
  let R  := {y  : ℝ | ∃ x ∈ M, f x = y}
  R = {y  : ℝ | -32 < y ∧ y < 4} := by

fbb795e1.theorem:
theorem arithmetic_seq_equal_sums_5  : 
  let t₁ (n  : ℕ)  := n * (5 * n + 5)  -- sum of first n terms of (5, 10, ...)
  let t₂ (n  : ℕ)  := n * (3 * n + 41) -- sum of first n terms of (22, 25, ...)
  ∀ n  : ℕ, n > 0 → (t₁ n = t₂ n ↔ n = 18) := by
